#include <stdio.h>
#include <stdlib.h>
#include <omp.h>
#include "../common.h"
#include "../util/timer/timer.h"
#ifdef TIMING
#include "../../util/timing.h"
#endif
#include "./kernel_gpu_opencl_wrapper_2.h"

void 
kernel_gpu_opencl_wrapper_2(knode *knodes,
							long knodes_elem,
							long knodes_mem,

							int order,
							long maxheight,
							int count,

							long *currKnode,
							long *offset,
							long *lastKnode,
							long *offset_2,
							int *start,
							int *end,
							int *recstart,
							int *reclength)
{

#ifdef TIMING
	struct timeval tv;
	struct timeval tv_total_start, tv_total_end;
	struct timeval tv_init_end;
	struct timeval tv_h2d_start, tv_h2d_end;
	struct timeval tv_d2h_start, tv_d2h_end;
	struct timeval tv_kernel_start, tv_kernel_end;
	struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
	struct timeval tv_close_start, tv_close_end;
	float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time= 0,
		  d2h_time = 0, close_time = 0, total_time = 0;
#endif

#ifdef  TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

#ifdef  TIMING
	gettimeofday(&tv_init_end, NULL);
	tvsub(&tv_init_end, &tv_total_start, &tv);
	init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef  TIMING
	gettimeofday(&tv_mem_alloc_end, NULL);
	tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
	mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	int local_work_size = order < 1024 ? order : 1024;
	int num_blocks = count;

	printf("# of blocks = %d, # of threads/block = %d (ensure that device can handle)\n", num_blocks, local_work_size);

#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

#pragma omp parallel for num_threads(num_blocks)
	for(int bid = 0; bid < count; bid++) {

		long current_knode = currKnode[bid];
		long last_knode = lastKnode[bid];
		long offset_val = offset[bid];
		long offset_2_val = offset_2[bid];
		int start_val = start[bid];
		int end_val = end[bid];

		int i;
		for(i = 0; i < maxheight; i++){

			int thid;
			int found_start = 0;
			int found_end = 0;
			int new_offset = offset_val;
			int new_offset_2 = offset_2_val;

			for(thid = 0; thid < local_work_size; thid++){
				if((knodes[current_knode].keys[thid] <= start_val) && (knodes[current_knode].keys[thid+1] > start_val)){
					if(knodes[current_knode].indices[thid] < knodes_elem){
						new_offset = knodes[current_knode].indices[thid];
					}
					found_start = 1;
				}
				if((knodes[last_knode].keys[thid] <= end_val) && (knodes[last_knode].keys[thid+1] > end_val)){
					if(knodes[last_knode].indices[thid] < knodes_elem){
						new_offset_2 = knodes[last_knode].indices[thid];
					}
					found_end = 1;
				}
			}

			if(found_start) {
				offset_val = new_offset;
			}
			if(found_end) {
				offset_2_val = new_offset_2;
			}

			current_knode = offset_val;
			last_knode = offset_2_val;
		}


		int thid;
		for(thid = 0; thid < local_work_size; thid++){
			if(knodes[current_knode].keys[thid] == start_val){
				recstart[bid] = knodes[current_knode].indices[thid];
				break;
			}
		}

		for(thid = 0; thid < local_work_size; thid++){
			if(knodes[last_knode].keys[thid] == end_val){
				reclength[bid] = knodes[last_knode].indices[thid] - recstart[bid] + 1;
				break;
			}
		}
	}

#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef  TIMING
	gettimeofday(&tv_close_start, NULL);
#endif

#ifdef  TIMING
	gettimeofday(&tv_close_end, NULL);
	tvsub(&tv_close_end, &tv_close_start, &tv);
	close_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
	printf("Time spent in different stages of GPU_CUDA KERNEL:\n");
	printf("Init: %f\n", init_time);
	printf("MemAlloc: %f\n", mem_alloc_time);
	printf("HtoD: %f\n", h2d_time);
	printf("Exec: %f\n", kernel_time);
	printf("DtoH: %f\n", d2h_time);
	printf("Close: %f\n", close_time);
	printf("Total: %f\n", total_time);
#endif

}
